import React from "react";
import "../styles/Professionals.css"; // Ensure this path is correct

const professionals = [
//     { id: 1, img: "professional1.jpg", alt: "Professional 1" },
//     { id: 2, img: "professional2.jpg", alt: "Professional 2" },
//     { id: 3, img: "professional3.jpg", alt: "Professional 3" },
//     { id: 4, img: "professional4.jpg", alt: "Professional 4" },
//     { id: 5, img: "professional5.jpg", alt: "Professional 5" },
//     { id: 6, img: "professional6.jpg", alt: "Professional 6" },
//     { id: 7, img: "professional7.jpg", alt: "Professional 7" },
//     { id: 8, img: "professional8.jpg", alt: "Professional 8" },
//     { id: 9, img: "professional9.jpg", alt: "Professional 9" },
//     { id: 10, img: "professional10.jpg", alt: "Professional 10" }
];

const Professionals = () => {
    return (
        <section className="professionals-section">
            <h2 className="section-title">OUR PROFESSIONALS</h2>
            <div className="professionals-grid">
                {professionals.map((pro) => (
                    <div key={pro.id} className="diamond">
                        <img src={require(`../assets/${pro.img}`)} alt={pro.alt} />
                    </div>
                ))}
            </div>
        </section>
    );
};

export default Professionals;
